<!DOCTYPE html><html><head><meta charset='utf-8'><title>Upload</title><link rel='stylesheet' href='automation_playground.css'></head><body><div class='container'><a href='/index.php'>Home</a><h2>Upload</h2><div class='panel'><input id='upload-file' type='file'><button id='upload-submit' class='btn'>Upload</button><div id='upload-result' class='result'>NO_FILE</div></div></div><script>document.getElementById('upload-submit').onclick=()=>{const f=document.getElementById('upload-file').files[0];document.getElementById('upload-result').textContent=f?`UPLOAD_SUCCESS|name=${f.name}|size=${f.size}|mime=${f.type}`:'NO_FILE'};</script></body></html>
